INSERT INTO rule_engine.rule_function (project_id,`scope`,func_code,func_name,description,params_json,return_type,impl_type,impl_script,impl_class,impl_method,impl_bean_name,status,create_time,update_time) VALUES
	 (0,'GLOBAL','idCardGender','身份证提取性别','根据身份证号提取性别：女返回0，男返回1，未知返回-1','[{"name":"idCard","type":"STRING","label":"身份证号"}]','NUMBER','SCRIPT','if (idCard == null) {
    return -1;
}
id = ("" + idCard).trim();
if (id.matches("[0-9]{17}[0-9Xx]")) {
    sexText = id.substring(16, 17);
} else if (id.matches("[0-9]{15}")) {
    sexText = id.substring(14, 15);
} else {
    return -1;
}
sexDigit = java.lang.Integer.parseInt(sexText);
return sexDigit % 2 == 0 ? 0 : 1;','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),
	 (0,'GLOBAL','idCardBirthDate','身份证提取出生日期','提取身份证出生日期并返回 yyyy-MM-dd；无法识别时返回 null','[{"name":"idCard","label":"身份证号","type":"STRING","example":"110105199001022317"}]','STRING','JAVA',NULL,'com.hengshucredit.rule.core.function.DecisionBuiltinFunctions','idCardBirthDate',NULL,1,'2026-07-07 00:34:31','2026-07-13 08:27:25'),
	 (0,'GLOBAL','strLeft','字符串提取前N位','提取字符串前N位；长度不够返回全部字符','[{"name":"text","type":"STRING","label":"字符串"},{"name":"n","type":"NUMBER","label":"位数"}]','STRING','SCRIPT','if (text == null) {
    return null;
}
if (n == null) {
    return "";
}
s = "" + text;
limit = n.intValue();
if (limit <= 0) {
    return "";
}
if (s.length() <= limit) {
    return s;
}
return s.substring(0, limit);','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),
	 (0,'GLOBAL','strRight','字符串提取后N位','提取字符串后N位；长度不够返回全部字符','[{"name":"text","type":"STRING","label":"字符串"},{"name":"n","type":"NUMBER","label":"位数"}]','STRING','SCRIPT','if (text == null) {
    return null;
}
if (n == null) {
    return "";
}
s = "" + text;
limit = n.intValue();
if (limit <= 0) {
    return "";
}
len = s.length();
if (len <= limit) {
    return s;
}
return s.substring(len - limit, len);','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),
	 (0,'GLOBAL','idCardAge','身份证计算年龄','按身份证出生日期计算年龄；YEAR 按年份差，FULL/DAY 按周岁计算','[{"name":"idCard","label":"身份证号","type":"STRING","example":"110105199001022317"},{"name":"currentDate","label":"计算日期","type":"OBJECT","example":"2025-01-02 12:30:00"},{"name":"calcMode","label":"计算方式","type":"STRING","example":"FULL"}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.DecisionBuiltinFunctions','idCardAge',NULL,1,'2026-07-07 00:34:31','2026-07-13 08:27:25'),
	 (0,'GLOBAL','regexMatch','字符串正则匹配','字符串匹配正则表达式，匹配返回1，未匹配或表达式无效返回0','[{"name":"text","type":"STRING","label":"字符串"},{"name":"regex","type":"STRING","label":"正则表达式"}]','NUMBER','SCRIPT','if (text == null || regex == null) {
    return 0;
}
try {
    return ("" + text).matches("" + regex) ? 1 : 0;
} catch (Exception ex) {
    return 0;
}','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),
	 (0,'GLOBAL','sum','序列求和','对列表、数组或 JSONPath 结果中的有效数字求和','[{"name":"data","label":"序列","type":"OBJECT","example":[1,2,3]}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.AggregateBuiltinFunctions','sum',NULL,1,'2026-07-08 04:16:22','2026-07-08 04:16:22'),
	 (0,'GLOBAL','count','序列计数','返回列表、数组或 JSONPath 结果的元素数量','[{"name":"data","label":"序列","type":"OBJECT","example":["A","B","C"]}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.AggregateBuiltinFunctions','count',NULL,1,'2026-07-08 04:16:22','2026-07-08 04:16:22'),
	 (0,'GLOBAL','max','序列最大值','返回序列中有效数字的最大值','[{"name":"data","label":"序列","type":"OBJECT","example":[3,9,2]}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.AggregateBuiltinFunctions','max',NULL,1,'2026-07-08 04:16:22','2026-07-08 04:16:22'),
